-- Disable body validation so LANGUAGE sql functions can forward-reference
-- each other within this file. (pg_dump does the same thing for the same
-- reason.) Without this, SQL functions parse-check at CREATE time and fail
-- on the first forward call site; plpgsql didn't, which is how this file
-- ever worked. Dependency order is still enforced at EXECUTION time.
SET check_function_bodies = off;

-- ============================================================================
-- LOOKUP FUNCTIONS
-- These functions perform lookups via foreign key relationships
-- ============================================================================

-- calc_transaction_types_name
-- Field: TransactionTypes.Name
-- Type: calculated | DataType: string | Returns: TEXT


CREATE OR REPLACE FUNCTION calc_transaction_types_name(p_transaction_type_id TEXT)
RETURNS TEXT AS $$
  SELECT ((SELECT NULLIF(transaction_type_id, '') FROM transaction_types WHERE transaction_type_id = p_transaction_type_id))::text;
$$ LANGUAGE sql STABLE;

-- calc_products_name
-- Field: Products.Name
-- Type: calculated | DataType: string | Returns: TEXT


CREATE OR REPLACE FUNCTION calc_products_name(p_product_id TEXT)
RETURNS TEXT AS $$
  SELECT ((SELECT NULLIF(product_id, '') FROM products WHERE product_id = p_product_id))::text;
$$ LANGUAGE sql STABLE;

-- calc_products_current_quantity
-- Field: Products.CurrentQuantity
-- Type: aggregation | DataType: integer | Returns: INTEGER


CREATE OR REPLACE FUNCTION calc_products_current_quantity(p_product_id TEXT)
RETURNS INTEGER AS $$
  SELECT ((SELECT COALESCE(SUM((quantity)::numeric), 0) FROM transactions WHERE product = p_product_id))::integer;
$$ LANGUAGE sql STABLE;

-- calc_products_is_low_stock
-- Field: Products.IsLowStock
-- Type: calculated | DataType: boolean | Returns: BOOLEAN


CREATE OR REPLACE FUNCTION calc_products_is_low_stock(p_product_id TEXT)
RETURNS BOOLEAN AS $$
  SELECT (calc_products_current_quantity(p_product_id) < (SELECT reorder_level FROM products WHERE product_id = p_product_id))::boolean;
$$ LANGUAGE sql STABLE;

-- calc_products_reorder_status
-- Field: Products.ReorderStatus
-- Type: calculated | DataType: string | Returns: TEXT


CREATE OR REPLACE FUNCTION calc_products_reorder_status(p_product_id TEXT)
RETURNS TEXT AS $$
  SELECT (CASE WHEN calc_products_is_low_stock(p_product_id) THEN ('This needs to be reordered !')::text ELSE ('In Stock')::text END)::text;
$$ LANGUAGE sql STABLE;

-- calc_transactions_product_name
-- Field: Transactions.ProductName
-- Type: lookup | DataType: string | Returns: TEXT
-- Lookup: Name from related Products


CREATE OR REPLACE FUNCTION calc_transactions_product_name(p_transaction_id TEXT)
RETURNS TEXT AS $$
  SELECT calc_products_name((SELECT product FROM transactions WHERE transaction_id = p_transaction_id));
$$ LANGUAGE sql STABLE;

-- calc_transactions_product_unit_price
-- Field: Transactions.ProductUnitPrice
-- Type: lookup | DataType: number | Returns: NUMERIC
-- Lookup: UnitPrice from related Products


CREATE OR REPLACE FUNCTION calc_transactions_product_unit_price(p_transaction_id TEXT)
RETURNS NUMERIC AS $$
  SELECT (SELECT unit_price::numeric FROM products WHERE product_id = (SELECT product FROM transactions WHERE transaction_id = p_transaction_id));
$$ LANGUAGE sql STABLE;

-- calc_transactions_transaction_type_name
-- Field: Transactions.TransactionTypeName
-- Type: lookup | DataType: string | Returns: TEXT
-- Lookup: Name from related TransactionTypes


CREATE OR REPLACE FUNCTION calc_transactions_transaction_type_name(p_transaction_id TEXT)
RETURNS TEXT AS $$
  SELECT calc_transaction_types_name((SELECT transaction_type FROM transactions WHERE transaction_id = p_transaction_id));
$$ LANGUAGE sql STABLE;

-- get_products_unit_price
-- Helper function: Get UnitPrice from Products by ProductId
-- Used for join-free cross-table references in aggregations

CREATE OR REPLACE FUNCTION get_products_unit_price(p_product_id TEXT)
RETURNS NUMERIC AS $$
  SELECT (SELECT unit_price FROM products WHERE product_id = p_product_id);
$$ LANGUAGE sql STABLE;

-- get_products_reorder_level
-- Helper function: Get ReorderLevel from Products by ProductId
-- Used for join-free cross-table references in aggregations

CREATE OR REPLACE FUNCTION get_products_reorder_level(p_product_id TEXT)
RETURNS INTEGER AS $$
  SELECT (SELECT reorder_level FROM products WHERE product_id = p_product_id);
$$ LANGUAGE sql STABLE;

-- get_transaction_types_description
-- Helper function: Get Description from TransactionTypes by TransactionTypeId
-- Used for join-free cross-table references in aggregations

CREATE OR REPLACE FUNCTION get_transaction_types_description(p_transaction_type_id TEXT)
RETURNS TEXT AS $$
  SELECT (SELECT description FROM transaction_types WHERE transaction_type_id = p_transaction_type_id);
$$ LANGUAGE sql STABLE;

-- calc_transactions_name
-- Field: Transactions.Name
-- Type: calculated | DataType: string | Returns: TEXT


CREATE OR REPLACE FUNCTION calc_transactions_name(p_transaction_id TEXT)
RETURNS TEXT AS $$
  SELECT ((SELECT NULLIF(transaction_id, '') FROM transactions WHERE transaction_id = p_transaction_id))::text;
$$ LANGUAGE sql STABLE;

-- calc_transactions_amount
-- Field: Transactions.Amount
-- Type: calculated | DataType: number | Returns: NUMERIC


CREATE OR REPLACE FUNCTION calc_transactions_amount(p_transaction_id TEXT)
RETURNS NUMERIC AS $$
  SELECT ((COALESCE(CASE WHEN ((SELECT quantity FROM transactions WHERE transaction_id = p_transaction_id))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN ((SELECT quantity FROM transactions WHERE transaction_id = p_transaction_id))::numeric ELSE NULL END, 0) * COALESCE(CASE WHEN (calc_transactions_product_unit_price(p_transaction_id))::text ~ '^-?[0-9]*\.?[0-9]+$' THEN (calc_transactions_product_unit_price(p_transaction_id))::numeric ELSE NULL END, 0)))::numeric;
$$ LANGUAGE sql STABLE;

